import java.util.*;

public class Solution {
    public static long solve(long[] nums) {
        int n = nums.length;
        if (n == 0) return 0;
        final int MAX = 1000000;
        boolean[] isPrime = new boolean[MAX + 1];
        int[] minPrimeFactor = new int[MAX + 1];
        for (int i = 0; i <= MAX; i++) {
            minPrimeFactor[i] = i;
        }
        for (int i = 2; i <= MAX; i++) {
            if (minPrimeFactor[i] == i) {
                if ((long) i * i <= MAX) {
                    for (int j = i * i; j <= MAX; j += i) {
                        if (minPrimeFactor[j] == j) {
                            minPrimeFactor[j] = i;
                        }
                    }
                }
            }
        }
        for (int i = 2; i <= MAX; i++) {
            isPrime[i] = (minPrimeFactor[i] == i);
        }

        Map<Integer, List<Integer>> primeToIndices = new HashMap<>();
        for (int j = 0; j < n; j++) {
            long x = nums[j];
            if (x <= 1) continue;
            long num = x;
            while (num > 1) {
                int p = minPrimeFactor[(int) num];
                primeToIndices.computeIfAbsent(p, k -> new ArrayList<>()).add(j);
                while (num % p == 0) {
                    num /= p;
                }
            }
        }

        int[] dist = new int[n];
        Arrays.fill(dist, -1);
        dist[0] = 0;
        Queue<Integer> queue = new LinkedList<>();
        queue.offer(0);
        Set<Integer> usedPrimes = new HashSet<>();

        while (!queue.isEmpty()) {
            int i = queue.poll();
            if (i - 1 >= 0 && dist[i - 1] == -1) {
                dist[i - 1] = dist[i] + 1;
                queue.offer(i - 1);
            }
            if (i + 1 < n && dist[i + 1] == -1) {
                dist[i + 1] = dist[i] + 1;
                queue.offer(i + 1);
            }
            long numVal = nums[i];
            if (numVal > 1 && numVal <= MAX) {
                int p = (int) numVal;
                if (isPrime[p] && !usedPrimes.contains(p)) {
                    usedPrimes.add(p);
                    List<Integer> indices = primeToIndices.get(p);
                    if (indices != null) {
                        for (int j : indices) {
                            if (j != i && dist[j] == -1) {
                                dist[j] = dist[i] + 1;
                                queue.offer(j);
                            }
                        }
                    }
                }
            }
        }

        return dist[n - 1];
    }
}
