            if (primeToRemainingSet.containsKey(p)) {
                Set<Integer> set = primeToRemainingSet.remove(p);
                for (int j : set) {
                    if (j == u) continue;
                    if (!visited[j]) {
                        visited[j] = true;
                        dist[j] = dist[u] + 1;
                        queue.add(j);
                    }
                }
            }
        }
    }
    return dist[n - 1];
}
